contracts/BondingCurve.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

/*
 BondingCurveBNB.sol
 - Linear bonding curve: P(s) = P0 + m * s/WAD  (price in BNB wei per token)
 - Buyers send BNB (payable). Contract takes 1% fee (sent to feeRecipient), uses net BNB to compute tokens out.
 - Sellers approve token -> sell(tokensIn) -> contract pays BNB net of 1% fee (fee forwarded).
 - Owner must deposit `curveAllocation` tokens to this contract before public buys.
 - Uses WAD (1e18) fixed point for price precision. token units are raw token units (with token decimals).
 - Curve starts at $5,000 market cap and ends at $50,000 market cap when all tokens are sold.
*/

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/utils/math/Math.sol";

// LOT-06 (Audit): SafeERC20 used for rescue/withdraw to prevent rug-pull and handle non-standard tokens

contract BondingCurveBNB is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable token; // token sold on curve (e.g., MemeToken)
    address public immutable feeRecipient;

    uint256 public constant WAD = 1e18;
    uint256 public constant FEE_BPS = 100; // 1% (100/10000)
    uint256 public constant BPS_BASE = 10000;

    // LOT-17 (Audit): P0 and m declared immutable - set only in constructor, gas savings on every quote read
    // Curve parameters (price units = BNB wei scaled as WAD)
    uint256 public immutable P0;   // starting price per token (WAD), equals (startFDV / totalSupply) * WAD
    uint256 public immutable m;    // slope (WAD per token)
    uint256 public sold;           // tokens sold so far (raw token units)
    uint256 public immutable curveAllocation; // total tokens allocated to this curve (raw units)
    bool public curveFinished;

    // AUDIT FIX (BUG-2,3,10): Track cumulative sell fees extracted from contract to adjust solvency checks
    uint256 public totalSellFeesExtracted;

    // AUDIT FIX (BUG-8): Time-locked sweep for burned/lost tokens that lock BNB forever
    uint256 public curveFinishedAt;
    uint256 public constant SWEEP_DELAY = 180 days;

    event DepositedTokens(address indexed from, uint256 amount);
    event Buy(address indexed buyer, uint256 bnbIn, uint256 tokensOut, uint256 fee);
    event Sell(address indexed seller, uint256 tokensIn, uint256 bnbOut, uint256 fee);
    event CurveFinished(uint256 sold);
    event LiquidityMigrated(address indexed to, uint256 amount);
    event BNBSwept(address indexed to, uint256 amount);
    // LOT-13 (Audit): Removed unused FeeRecipientChanged event - feeRecipient is immutable and never changed

    /// @dev LOT-32 (Audit Round 2): Payable constructor. If msg.value >= 1 wei, validates feeRecipient with a 1-wei
    /// transfer (zero-value probe is insufficient — some contracts accept 0 but revert on non-zero). Refunds remainder.
    constructor(
        address _token,
        uint256 _P0_wad,
        uint256 _m_wad,
        uint256 _curveAllocation,
        address _feeRecipient,
        address _owner
    ) payable {
        require(_token != address(0), "token 0");
        require(_feeRecipient != address(0), "feeRecipient 0");

        // AUDIT FIX (BUG-17): Reject degenerate curve parameters that produce broken/free curves
        require(_P0_wad > 0, "P0 must be > 0");
        require(_m_wad > 0, "m must be > 0");
        require(_curveAllocation > 0, "curveAllocation must be > 0");

        // AUDIT FIX (BUG-22): Bonding curve math requires 18-decimal tokens; reject non-18
        require(IERC20Metadata(_token).decimals() == 18, "requires 18 decimals");

        if (msg.value >= 1) {
            (bool ok,) = payable(_feeRecipient).call{value: 1}("");
            require(ok, "feeRecipient cannot receive BNB");
            if (msg.value > 1) {
                (bool refund,) = payable(msg.sender).call{value: msg.value - 1}("");
                require(refund, "refund failed");
            }
        } else {
            (bool testSend,) = payable(_feeRecipient).call{value: 0}("");
            require(testSend, "feeRecipient cannot receive BNB");
        }
        token = IERC20(_token);
        P0 = _P0_wad;
        m = _m_wad;
        curveAllocation = _curveAllocation;
        feeRecipient = _feeRecipient;
        _transferOwnership(_owner);
    }

    // Get current market cap in USD (approximate, based on BNB price)
    // This is a view function for reference - actual pricing is in BNB
    // Market cap = Current Price × Total Supply (curveAllocation)
    function getCurrentMarketCapUSD(uint256 bnbPriceUSD) external view returns (uint256) {
        // Calculate current price at the current sold amount
        uint256 currentPriceBNB = priceAt(sold); // Price in BNB (WAD scaled)

        // Market cap = currentPriceBNB × curveAllocation × bnbPriceUSD / (WAD × WAD)
        // currentPriceBNB is in WAD (18 decimals)
        // curveAllocation is in raw token units (18 decimals)
        // bnbPriceUSD is in WAD (18 decimals)
        // Result: (WAD × WAD × WAD) / (WAD × WAD) = WAD (18 decimals) ✓
        uint256 currentPriceUSD = (currentPriceBNB * bnbPriceUSD) / WAD; // Price in USD per token (WAD scaled)
        uint256 marketCapUSD = (currentPriceUSD * curveAllocation) / WAD; // Total market cap in USD (WAD scaled)

        return marketCapUSD;
    }

    // PRICE HELPERS
    // Price at sold s: P(s) = P0 + m * s / curveAllocation
    // This ensures price increases gradually from P0 (when s=0) to P0+m (when s=curveAllocation)
    function priceAt(uint256 s) public view returns (uint256) {
        if (curveAllocation == 0) return P0;
        return P0 + (m * s) / curveAllocation;
    }

    /// @dev LOT-18 (Audit): Quadratic term helper.
    /// term2 = m * ds^2 / (2 * curveAllocation * WAD)
    /// AUDIT FIX (BUG-15,21): Replaced multi-branch integer arithmetic with Math.mulDiv for full
    /// 512-bit intermediate precision. Eliminates rounding divergence that caused solvency deficit,
    /// non-additive quotes, and path-dependent pricing across all token magnitudes including sub-WAD.
    function _quadraticTerm(uint256 ds) internal view returns (uint256) {
        if (ds == 0 || curveAllocation == 0) return 0;
        uint256 dsSquaredOverWad = Math.mulDiv(ds, ds, WAD);
        return Math.mulDiv(m, dsSquaredOverWad, 2 * curveAllocation);
    }

    // Cost (in wei) to buy ds tokens from state s:
    // Price at s: P(s) = P0 + m * s / curveAllocation (in WAD units)
    // Cost = P(s)*ds/WAD + 0.5*m*ds^2/(curveAllocation*WAD) = term1 + term2
    function buyQuoteFor(uint256 s, uint256 ds) public view returns (uint256) {
        if (ds == 0) return 0;
        if (curveAllocation == 0) return 0;
        uint256 b = P0 + (m * s) / curveAllocation;
        uint256 term1 = (b * ds) / WAD;
        return term1 + _quadraticTerm(ds);
    }

    /// @notice Quote returned when selling ds tokens from state s.
    /// AUDIT FIX (BUG-1,4,5,6 — Root Cause): Compute base price at (s - ds) — the bottom of the
    /// sell range — instead of s (the top). This makes sellQuoteFor(s, ds) == buyQuoteFor(s - ds, ds),
    /// eliminating the rounding asymmetry that caused insolvency after every buy, sell-quote exceeding
    /// buy-quote, and the impossible buy-sell roundtrip.
    function sellQuoteFor(uint256 s, uint256 ds) public view returns (uint256) {
        require(ds <= s, "ds > s");
        if (ds == 0) return 0;
        if (curveAllocation == 0) return 0;
        uint256 b = P0 + (m * (s - ds)) / curveAllocation;
        uint256 term1 = (b * ds) / WAD;
        return term1 + _quadraticTerm(ds);
    }

    /// @notice Solve for ds given netQuote using binary search.
    /// @dev AUDIT NOTE (BUG-11): Splitting a large buy into many small buys may yield ~0.00005% more
    /// tokens due to integer rounding in the binary search. This is a known limitation; the gas cost
    /// of splitting exceeds the rounding profit. Similarly (BUG-12), splitting sells into smaller
    /// chunks compounds rounding loss. Both are inherent to discrete-step binary search over an
    /// integer integral. Math.mulDiv in _quadraticTerm minimizes but cannot eliminate this.
    function tokensForQuote(uint256 s, uint256 netQuote) public view returns (uint256) {
        if (netQuote == 0) return 0;
        uint256 remaining = curveAllocation - s;
        if (remaining == 0) return 0;

        // Calculate upper bound using linear estimate
        uint256 currentPrice = priceAt(s);
        if (currentPrice == 0) return 0;

        // Linear estimate: tokens ≈ (netQuote * WAD) / currentPrice
        // currentPrice is in WAD (price per token scaled by WAD)
        // netQuote is in wei (BNB wei)
        // We need: tokens = netQuote / (currentPrice / WAD) = (netQuote * WAD) / currentPrice
        uint256 linearEstimate;
        if (netQuote <= type(uint256).max / WAD) {
            linearEstimate = (netQuote * WAD) / currentPrice;
        } else {
            // If multiplication would overflow, use alternative calculation
            // currentPrice / WAD gives price in wei per token
            uint256 priceInWei = currentPrice / WAD;
            if (priceInWei == 0) return 0; // Price too small
            linearEstimate = netQuote / priceInWei;
        }

        uint256 upperBound = linearEstimate < remaining ? linearEstimate : remaining;
        if (upperBound == 0) return 0;

        // Binary search: find maximum tokens that can be bought
        if (upperBound == 0) return 0;

        uint256 low = 1;
        uint256 high = upperBound;
        uint256 answer = 0;
        // LOT-27 (Audit): 128 iterations sufficient for full uint256 range; reduces unpredictable gas
        uint256 maxIterations = 128;

        // Standard binary search to find the maximum tokens we can buy
        while (low <= high && maxIterations > 0) {
            maxIterations--;
            uint256 mid = (low + high) / 2;

            if (mid == 0) break;

            uint256 cost = buyQuoteFor(s, mid);

            if (cost <= netQuote) {
                answer = mid;
                if (low == high) break;
                if (mid == high) break; // Avoid infinite loop
                low = mid + 1;
            } else {
                if (mid <= 1) break;
                high = mid - 1;
            }
        }

        // Validate the answer
        if (answer > 0) {
            uint256 answerCost = buyQuoteFor(s, answer);
            // If cost is 0 (rounded), the amount is too small - return 0
            if (answerCost == 0) {
                return 0;
            }
            // Ensure answer is actually affordable
            if (answerCost > netQuote) {
                // Answer is too expensive, try one less
                if (answer > 1) {
                    answer--;
                    answerCost = buyQuoteFor(s, answer);
                    if (answerCost == 0 || answerCost > netQuote) {
                        return 0;
                    }
                } else {
                    return 0;
                }
            }
            return answer;
        }

        // Binary search didn't find anything - this shouldn't happen if linear estimate is correct
        // But try one more time with a smaller upper bound
        // Check if we can buy at least 1 wei
        uint256 costFor1 = buyQuoteFor(s, 1);
        if (costFor1 > 0 && costFor1 <= netQuote) {
            // We can buy at least 1 wei, so do a more careful binary search
            // Start from a minimum that we know works
            uint256 minTokens = 1;
            uint256 maxTokens = upperBound;

            // Find the maximum by checking powers of 2
            uint256 testAmount = minTokens;
            while (testAmount <= maxTokens) {
                uint256 testCost = buyQuoteFor(s, testAmount);
                if (testCost > 0 && testCost <= netQuote) {
                    answer = testAmount;
                    testAmount = testAmount * 2;
                    if (testAmount == 0) break; // Overflow
                } else {
                    break;
                }
            }

            // Now binary search between answer and answer*2 (or maxTokens)
            if (answer > 0) {
                low = answer;
                high = (answer * 2 < maxTokens) ? answer * 2 : maxTokens;

                for (uint256 i = 0; i < 100 && low <= high; i++) {
                    uint256 mid = (low + high) / 2;
                    uint256 cost = buyQuoteFor(s, mid);

                    if (cost > 0 && cost <= netQuote) {
                        answer = mid;
                        if (low == high) break;
                        low = mid + 1;
                    } else {
                        if (mid <= answer) break;
                        high = mid - 1;
                    }
                }
            }
        }

        return answer;
    }

    // --- Admin / deposits ---

    /// owner must pre-fund the curve with tokens
    /// LOT-31 (Audit Round 2): Use SafeERC20 for compatibility with non-standard ERC-20 (e.g. USDT that doesn't return bool)
    function depositCurveTokens(uint256 amount) external nonReentrant onlyOwner {
        require(amount > 0, "amount>0");
        token.safeTransferFrom(msg.sender, address(this), amount);
        emit DepositedTokens(msg.sender, amount);
    }

    // Fee recipient is immutable, cannot be changed

    // LOT-06 (Audit): Withdraw only excess tokens. LOT-34: Owner can withdraw above active allocation; trust assumption.
    function withdrawToken(address to, uint256 amount) external onlyOwner {
        require(to != address(0), "zero");
        uint256 activeBalance = curveAllocation - sold;
        uint256 currentBalance = token.balanceOf(address(this));
        require(currentBalance - amount >= activeBalance, "cannot withdraw active tokens");
        token.safeTransfer(to, amount);
    }

    // LOT-06 (Audit): Cannot rescue curve's own token; other ERC20 only (e.g. airdrops)
    function rescueERC20(address tokenAddr, address to, uint256 amount) external onlyOwner {
        require(tokenAddr != address(token), "cannot rescue curve token");
        IERC20(tokenAddr).safeTransfer(to, amount);
    }
    // LOT-06 (Audit): Rescue BNB only if curve remains solvent. LOT-34: Combined with markCurveFinished, owner can extract within solvency; trust assumption.
    // AUDIT FIX (BUG-14): Guard against underflow when amount > balance (was Panic(0x11), now readable error).
    // AUDIT FIX (BUG-2,3,10): Subtract totalSellFeesExtracted from required reserve — fees already left the contract.
    function rescueBNB(address payable to, uint256 amount) external onlyOwner {
        require(to != payable(address(0)), "zero");
        require(amount <= address(this).balance, "insufficient balance");
        uint256 grossRequired = sellQuoteFor(sold, sold);
        uint256 requiredBNB = grossRequired > totalSellFeesExtracted
            ? grossRequired - totalSellFeesExtracted
            : 0;
        require(address(this).balance - amount >= requiredBNB, "would make curve insolvent");
        (bool sent,) = to.call{value: amount}("");
        require(sent, "BNB send failed");
    }

    // LOT-34 (Audit Round 2): Centralization — owner can unilaterally halt buys. Documented admin trust assumption.
    // For stronger protection consider TimelockController (24–48h delay) or renouncing ownership after launch.
    // AUDIT FIX (BUG-8): Record curveFinishedAt for time-locked sweep of permanently stuck BNB.
    function markCurveFinished() external onlyOwner {
        curveFinished = true;
        curveFinishedAt = block.timestamp;
        emit CurveFinished(sold);
    }

    // --------------------
    // BUY (payable) - BNB
    // --------------------
    // LOT-21 (Audit): deadline prevents stale transactions (e.g. Four.Meme-style sandwich on BSC)
    function buyWithBNB(uint256 minTokensOut, uint256 deadline) external payable nonReentrant {
        require(block.timestamp <= deadline, "transaction expired");
        require(!curveFinished, "curve finished");
        require(msg.value > 0, "send BNB");

        uint256 fee = (msg.value * FEE_BPS) / BPS_BASE;
        if (fee > 0) {
            (bool ok,) = payable(feeRecipient).call{value: fee}("");
            require(ok, "fee transfer failed");
        }
        uint256 netQuote = msg.value - fee;

        uint256 ds = tokensForQuote(sold, netQuote);
        require(ds > 0, "insufficient BNB");

        uint256 remaining = curveAllocation - sold;
        if (ds > remaining) ds = remaining;

        uint256 actualCost = buyQuoteFor(sold, ds);
        if (actualCost < netQuote) {
            uint256 refund = netQuote - actualCost;
            if (refund > 0) {
                (bool sent,) = payable(msg.sender).call{value: refund}("");
                require(sent, "refund failed");
            }
        } else if (actualCost > netQuote) {
            (bool r,) = payable(msg.sender).call{value: netQuote}("");
            require(r, "refund failed");
            revert("quote short");
        }

        require(ds >= minTokensOut, "slippage");

        // LOT-24 (Audit): CEI — update state before external call
        sold += ds;
        // LOT-31 (Audit Round 2): Use SafeERC20 for compatibility with non-standard ERC-20
        token.safeTransfer(msg.sender, ds);

        if (sold >= curveAllocation) {
            curveFinished = true;
            curveFinishedAt = block.timestamp; // AUDIT FIX (BUG-8)
            emit CurveFinished(sold);
        }

        emit Buy(msg.sender, msg.value, ds, fee);
    }

    // --------------------
    // SELL (receive BNB)
    // --------------------
    // LOT-01 (Audit): Enforce minQuoteOut for slippage protection; LOT-21: deadline for stale txs
    // LOT-30 (Audit Round 2): Strict CEI — update sold BEFORE any external call (including transferFrom).
    // LOT-31 (Audit Round 2): Use safeTransferFrom for non-standard ERC-20 compatibility.
    // AUDIT FIX (BUG-13,16): Block sells after curveFinished to protect BNB reserved for DEX migration.
    function sell(uint256 tokensIn, uint256 minQuoteOut, uint256 deadline) external nonReentrant {
        require(block.timestamp <= deadline, "transaction expired");
        require(!curveFinished, "curve finished"); // AUDIT FIX (BUG-13,16)
        require(tokensIn > 0, "zero tokens");
        require(tokensIn <= sold, "cannot sell more than sold");

        uint256 grossOut = sellQuoteFor(sold, tokensIn);
        require(grossOut > 0, "quote too small");

        uint256 fee = (grossOut * FEE_BPS) / BPS_BASE;
        uint256 netOut = grossOut - fee;
        require(netOut >= minQuoteOut, "slippage");

        require(address(this).balance >= grossOut, "insufficient liquidity");

        // CEI: update ALL state before ANY external calls (LOT-30)
        sold -= tokensIn;
        // AUDIT FIX (BUG-2,3,10): Track cumulative sell fees so rescueBNB solvency check
        // accounts for BNB that already left the contract as fees.
        totalSellFeesExtracted += fee;

        token.safeTransferFrom(msg.sender, address(this), tokensIn);

        (bool sent,) = payable(msg.sender).call{value: netOut}("");
        require(sent, "pay seller failed");

        if (fee > 0) {
            (bool ok,) = payable(feeRecipient).call{value: fee}("");
            require(ok, "fee transfer failed");
        }

        emit Sell(msg.sender, tokensIn, netOut, fee);
    }

    // --- DEX Migration & Sweep ---

    /// @notice AUDIT FIX (BUG-9): Migrate BNB to DEX after curve finishes. Since sells are blocked
    /// after curveFinished (BUG-13 fix), no reserve is needed and all BNB can go to DEX LP.
    function migrateLiquidity(address payable to) external onlyOwner {
        require(curveFinished, "not finished");
        require(to != payable(address(0)), "zero");
        uint256 balance = address(this).balance;
        require(balance > 0, "no BNB");
        (bool ok,) = to.call{value: balance}("");
        require(ok, "transfer failed");
        emit LiquidityMigrated(to, balance);
    }

    /// @notice AUDIT FIX (BUG-8): Time-locked sweep for BNB permanently stuck due to burned/lost tokens.
    /// Only available 180 days after curveFinished — gives token holders ample time to sell on DEX.
    function sweepRemainingBNB(address payable to) external onlyOwner {
        require(curveFinished, "not finished");
        require(curveFinishedAt > 0, "finishedAt not set");
        require(block.timestamp >= curveFinishedAt + SWEEP_DELAY, "too early");
        require(to != payable(address(0)), "zero");
        uint256 balance = address(this).balance;
        (bool ok,) = to.call{value: balance}("");
        require(ok, "transfer failed");
        emit BNBSwept(to, balance);
    }

    // receive fallback (pull in BNB if someone sends accidentally)
    receive() external payable {}
}

contracts/BondingCurveFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./BondingCurve.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";

/**
 * @title BondingCurveFactory
 * @notice Factory contract to deploy bonding curves for tokens
 * @dev Automatically calculates bonding curve parameters based on USD market cap targets
 * @dev Uses Chainlink Price Feed to get real-time BNB/USD price
 */
contract BondingCurveFactory is Ownable {
    address public immutable feeRecipient;
    AggregatorV3Interface public immutable bnbPriceFeed;

    // LOT-33 (Audit Round 2): Restrict createBondingCurve to authorized callers (e.g. TokenFactory) to prevent spam/fraud
    mapping(address => bool) public authorizedCallers;

    modifier onlyAuthorized() {
        require(authorizedCallers[msg.sender] || msg.sender == owner(), "unauthorized");
        _;
    }

    uint256 public constant START_MARKET_CAP_USD = 5000; // $5,000 (initial market cap at start)
    uint256 public constant END_MARKET_CAP_USD = 76963; // ~$76,963 (target market cap at end, matching four.meme)
    uint256 public constant CURVE_TOKENS = 1_000_000_000; // 1B tokens total (800M tradable, 200M locked for DEX)
    // LOT-15 (Audit): Removed unused TRADABLE_TOKENS constant
    uint256 public constant STALENESS_THRESHOLD = 3600; // LOT-04 (Audit): 1 hour - BNB/USD feed heartbeat ~60s
    // Target initial price in BNB (matching four.meme: 0.000000005798 BNB per token)
    // From four.meme expected amounts:
    //   - 0.00099 BNB → 170,734 tokens → P0 ≈ 5.798e-9
    //   - 0.0099 BNB → 1,704,902 tokens
    //   - 0.099 BNB → 16,808,861 tokens
    //   - 0.99 BNB → 147,334,426 tokens
    uint256 public constant TARGET_P0_BNB_NUMERATOR = 5798; // 0.000000005798 = 5798 / 1e12
    uint256 public constant TARGET_P0_BNB_DENOMINATOR = 1e12;
    uint256 public constant WAD = 1e18;
    uint256 public constant PRICE_FEED_DECIMALS = 8; // Chainlink price feeds use 8 decimals

    event BondingCurveCreated(
        address indexed token,
        address indexed bondingCurve,
        uint256 p0_wad,
        uint256 m_wad,
        uint256 curveAllocation,
        uint256 bnbPriceUSD
    );
    event AuthorizedCallerSet(address indexed caller, bool authorized);

    /**
     * @param _feeRecipient Address to receive 1% fees from buy/sell
     * @param _bnbPriceFeed Address of Chainlink BNB/USD price feed
     *                      BSC Mainnet: 0x0567F2323251f0Aab15c8dFbB7a6333D0d8771a3
     *                      BSC Testnet: Check Chainlink docs for testnet address
     */
    constructor(address _feeRecipient, address _bnbPriceFeed) {
        require(_feeRecipient != address(0), "feeRecipient 0");
        require(_bnbPriceFeed != address(0), "priceFeed 0");
        feeRecipient = _feeRecipient;
        bnbPriceFeed = AggregatorV3Interface(_bnbPriceFeed);
        _transferOwnership(msg.sender);
    }

    /**
     * @notice Get latest BNB price from Chainlink Price Feed
     * LOT-04 (Audit): Staleness validation via updatedAt; roundId check.
     * AUDIT FIX (BUG-23): Validate answeredInRound >= roundId to reject stale carried-over answers.
     * Chainlink V3 still returns answeredInRound; when answeredInRound < roundId the price was
     * carried forward from an earlier round without a fresh update.
     * @return price BNB price in USD with 18 decimals (WAD)
     */
    function getLatestBNBPrice() public view returns (uint256 price) {
        (
            uint80 roundId,
            int256 rawPrice,
            /* uint startedAt */,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = bnbPriceFeed.latestRoundData();

        require(rawPrice > 0, "Invalid price");
        require(roundId != 0, "Invalid round");
        require(updatedAt != 0 && updatedAt <= block.timestamp, "Invalid timestamp");
        require(block.timestamp - updatedAt <= STALENESS_THRESHOLD, "Stale price");
        // AUDIT FIX (BUG-23): Reject stale carried-over oracle answers
        require(answeredInRound >= roundId, "Stale answer");

        price = uint256(rawPrice) * (10 ** 10);
    }

    /**
     * @notice Calculate bonding curve parameters to match four.meme pricing exactly.
     * LOT-09 (Audit): bnbPriceUSD is fetched and returned for off-chain use; P0/m are BNB-denominated (fixed targets), not dynamically derived from USD here.
     * AUDIT NOTE (BUG-24): P0 and m are BNB-denominated constants — they do NOT vary with BNB/USD price.
     * The Chainlink feed is used only to return bnbPriceUSD as informational metadata. START_MARKET_CAP_USD
     * and END_MARKET_CAP_USD are reference documentation only and are not used in calculations.
     * If the feed is stale, curve deployment will fail even though the price has no effect on P0/m.
     * To decouple deployment from feed availability, consider passing bnbPriceUSD as an off-chain parameter.
     * @dev Uses multiple target points to calculate m accurately:
     *      - 0.00099 BNB → 170,734 tokens
     *      - 0.0099 BNB → 1,704,902 tokens
     *      - 0.099 BNB → 16,808,861 tokens
     *      - 0.99 BNB → 147,334,426 tokens
     *      
     *      The formula: Cost = P0*s + 0.5*m*s^2/curveAllocation
     *      Solving for m using the largest point (0.99 BNB) for accuracy
     * @return p0_wad Starting price in BNB wei per token (WAD scaled)
     * @return m_wad Slope in BNB wei per token per token (WAD scaled)
     * @return bnbPriceUSD Current BNB price in USD (WAD scaled, 18 decimals)
     */
    function calculateCurveParams() public view returns (
        uint256 p0_wad,
        uint256 m_wad,
        uint256 bnbPriceUSD
    ) {
        // Fetch real-time BNB price from Chainlink (8 decimals -> 18 decimals)
        bnbPriceUSD = getLatestBNBPrice(); // Now in WAD (18 decimals)

        // Set P0 directly to target initial price: 5.798e-9 BNB per token (matching four.meme)
        // P0 = 5798 / 1e12 * 1e18 = 5798 * 1e6 = 5798000000 (in WAD)
        p0_wad = (TARGET_P0_BNB_NUMERATOR * WAD) / TARGET_P0_BNB_DENOMINATOR;

        // Calculate m to match the expected token amounts at initial state (s=0)
        // Expected: 0.99 BNB → 147,334,426 tokens
        // New formula: P(s) = P0 + (m * s) / curveAllocation
        // Cost from s=0: Cost = (P0 * ds) / WAD + (m * ds^2) / (2 * curveAllocation * WAD)
        // Note: m is stored as m_wad (already in WAD units), so m = m_wad
        // Solving for m_wad: (m_wad * ds^2) / (2 * curveAllocation * WAD) = Cost - (P0 * ds) / WAD
        // m_wad * ds^2 = 2 * (Cost - (P0 * ds) / WAD) * curveAllocation * WAD
        // m_wad = 2 * (Cost - (P0 * ds) / WAD) * curveAllocation * WAD / ds^2
        uint256 targetTokensSold = 147_334_426 * (10 ** 18); // In raw token units (WAD)
        uint256 targetCostWei = 99 * (10 ** 16); // 0.99 BNB net (after 1% fee from 1 BNB input)
        uint256 curveAllocation = CURVE_TOKENS * (10 ** 18); // 1B tokens in raw units (18 decimals)

        // P0 term: (P0 * ds) / WAD (in wei)
        uint256 p0TermWei = (p0_wad * targetTokensSold) / WAD;

        // Calculate m if there's a cost difference
        if (targetCostWei > p0TermWei && targetTokensSold > 0 && curveAllocation > 0) {
            uint256 costDiffWei = targetCostWei - p0TermWei;

            // Calculate ds^2 to avoid overflow
            // ds = 147334426 * 10^18
            // ds^2 = (147334426 * 10^18)^2 = 147334426^2 * 10^36
            // We need: m_wad = 2 * costDiffWei * curveAllocation * WAD / ds^2

            uint256 twoCostDiff = 2 * costDiffWei;

            // Calculate step by step to avoid overflow
            // m_wad = (2 * costDiff * curveAllocation * WAD) / ds^2
            // ds^2 = targetTokensSold^2 (36 decimals)
            // To avoid calculating huge ds^2, use: dsSquared = (ds/WAD)^2 (no decimals)
            // Then ds^2 = dsSquared * WAD^2
            // So: m_wad = (2 * costDiff * curveAllocation * WAD) / (dsSquared * WAD^2)
            // = (2 * costDiff * curveAllocation) / (dsSquared * WAD)

            uint256 dsSquared = (targetTokensSold / WAD) * (targetTokensSold / WAD); // (ds/WAD)^2, no decimals
            if (dsSquared == 0) dsSquared = 1; // Avoid division by zero

            // Calculate: (2 * costDiff * curveAllocation) / (dsSquared * WAD)
            if (twoCostDiff <= type(uint256).max / curveAllocation) {
                uint256 numerator = twoCostDiff * curveAllocation; // 18 + 18 = 36 decimals
                // Divide by (dsSquared * WAD)
                if (dsSquared <= type(uint256).max / WAD) {
                    uint256 denominator = dsSquared * WAD; // 0 + 18 = 18 decimals
                    m_wad = numerator / denominator; // 36 - 18 = 18 decimals (WAD) ✓
                } else {
                    // Divide numerator by WAD first, then by dsSquared
                    uint256 numeratorOverWad = numerator / WAD; // 36 - 18 = 18 decimals
                    m_wad = numeratorOverWad / dsSquared; // 18 - 0 = 18 decimals (WAD) ✓
                }
            } else {
                // Divide costDiff first to avoid overflow
                // Calculate: (2 * costDiff) / dsSquared, then * curveAllocation, then / WAD
                uint256 quotient = twoCostDiff / dsSquared;
                if (quotient > 0 && quotient <= type(uint256).max / curveAllocation) {
                    uint256 temp = quotient * curveAllocation; // 0 + 18 = 18 decimals
                    m_wad = temp / WAD; // 18 - 18 = 0 decimals... wait that's wrong!
                    // Actually, we need: m_wad = (2 * costDiff * curveAllocation) / (dsSquared * WAD)
                    // = ((2 * costDiff) / dsSquared) * curveAllocation / WAD
                    // But (2 * costDiff) / dsSquared might lose precision
                    // Better: calculate (2 * costDiff * curveAllocation) first, then divide
                    // If that overflows, use alternative method
                    uint256 costDiffTimesCurveAlloc = costDiffWei * curveAllocation;
                    if (costDiffTimesCurveAlloc <= type(uint256).max / 2) {
                        uint256 numerator = costDiffTimesCurveAlloc * 2; // 18 + 18 = 36 decimals
                        if (dsSquared <= type(uint256).max / WAD) {
                            m_wad = numerator / (dsSquared * WAD); // 36 - 18 = 18 decimals ✓
                        } else {
                            m_wad = (numerator / WAD) / dsSquared; // (36-18) - 0 = 18 decimals ✓
                        }
                    } else {
                        m_wad = 0; // Would overflow
                    }
                } else {
                    m_wad = 0; // Would overflow
                }
            }
        } else {
            m_wad = 0;
        }
    }

    /// @notice LOT-33 (Audit Round 2): Only owner or authorized callers (e.g. TokenFactory) can deploy curves.
    function setAuthorizedCaller(address caller, bool authorized) external onlyOwner {
        authorizedCallers[caller] = authorized;
        emit AuthorizedCallerSet(caller, authorized);
    }

    /**
     * @notice Create a bonding curve for a token
     * LOT-33 (Audit Round 2): onlyAuthorized — register TokenFactory via setAuthorizedCaller(factory, true) after deploy.
     * @param _token Token address
     * @param _tokenDecimals Token decimals (usually 18)
     * @param _owner Owner of the bonding curve
     * @return bondingCurve Address of the deployed bonding curve
     */
    function createBondingCurve(
        address _token,
        uint8 _tokenDecimals,
        address _owner
    ) external onlyAuthorized returns (address bondingCurve) {
        require(_token != address(0), "token 0");
        require(_owner != address(0), "owner 0");
        // LOT-19 (Audit): Bonding curve math assumes 18-decimal tokens
        require(_tokenDecimals == 18, "bonding curves require 18 decimals");

        // Calculate curve parameters using real-time BNB price from Chainlink
        (uint256 p0_wad, uint256 m_wad, uint256 bnbPriceUSD) = calculateCurveParams();
        // Use 1B tokens in curve (flatter curve), but only 800M will be tradable
        // The remaining 200M are locked and will go to DEX when curve finishes
        uint256 curveAllocation = CURVE_TOKENS * (10 ** _tokenDecimals);

        BondingCurveBNB curve = new BondingCurveBNB(
            _token,
            p0_wad,
            m_wad,
            curveAllocation,
            feeRecipient,
            _owner
        );

        bondingCurve = address(curve);
        emit BondingCurveCreated(_token, bondingCurve, p0_wad, m_wad, curveAllocation, bnbPriceUSD);
    }
}

contracts/MemeToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MemeToken is Ownable, ReentrancyGuard {
    // Basic token properties
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;

    // Anti-sniper protection
    bool public antiSniperEnabled;
    uint256 public maxWallet;
    uint256 public maxTransaction;
    uint256 public cooldownPeriod;
    /// LOT-34 (Audit Round 2): Once locked, owner can only relax limits (not tighten) to prevent weaponizing anti-sniper
    bool public antiSniperLocked;

    // Rich metadata
    string public description;
    string public logoURL;
    string public website;
    string public github;
    string public twitter;
    string[] public projectCategories;
    string public customAddressSuffix;

    // Buy options and pricing tiers
    uint256[] public buyOptions;

    // Transfer tracking and exclusions
    mapping(address => uint256) public balanceOf;
    mapping(address => uint256) public lastTransferTime;
    mapping(address => bool) public excludedFromLimits;

    // ERC20 allowance for approve/transferFrom
    mapping(address => mapping(address => uint256)) public allowance;

    // Events
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event AntiSniperSettingsUpdated(bool enabled, uint256 maxWallet, uint256 maxTransaction, uint256 cooldown);
    event MetadataUpdated(string description, string logoURL, string website, string github, string twitter);
    event BuyOptionsUpdated(uint256[] buyOptions);
    event ExcludedAddressUpdated(address indexed account, bool excluded);

    constructor(
        string memory _name,
        string memory _symbol,
        uint8 _decimals,
        address _creator,
        uint256 _totalSupply,
        string memory _description,
        string memory _logoURL,
        string memory _website,
        string memory _github,
        string memory _twitter,
        string[] memory _projectCategories,
        uint256[] memory _buyOptions
    ) ReentrancyGuard() {
        require(_totalSupply > 0, "Total supply must be greater than 0");

        name = _name;
        symbol = _symbol;
        decimals = _decimals;
        totalSupply = _totalSupply * (10 ** _decimals);

        // Set default anti-sniper values
        antiSniperEnabled = true;
        maxWallet = _totalSupply * (10 ** _decimals);
        maxTransaction = _totalSupply * (10 ** _decimals);
        cooldownPeriod = 30;

        // Set initial balance for creator
        balanceOf[_creator] = totalSupply;

        // Exclude creator from limits
        excludedFromLimits[_creator] = true;

        // Transfer ownership to creator
        _transferOwnership(_creator);

        // Set metadata
        _setMetadata(_description, _logoURL, _website, _github, _twitter, _projectCategories, _buyOptions);

        emit Transfer(address(0), _creator, totalSupply);
    }

    // LOT-10 (Audit): Standard EIP-20 approve; known race if spender front-runs. Consider EIP-2612 permit() for gasless approvals.
    function approve(address spender, uint256 value) external returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    // LOT-16 (Audit): Removed nonReentrant — no external calls in transfer; saves gas and allows use inside other nonReentrant flows
    // AUDIT FIX (BUG-18): Check sender and recipient limits independently. Previously, when the sender
    // was excluded (e.g., the bonding curve), ALL limits were bypassed including maxWallet on the recipient.
    // Now: sender exclusion only skips sender-side checks (maxTransaction, cooldown). Recipient maxWallet
    // is always enforced unless the recipient is also excluded.
    function transferFrom(address from, address to, uint256 value) external returns (bool) {
        require(balanceOf[from] >= value, "Insufficient balance");
        require(to != address(0), "Transfer to zero address");

        if (from != msg.sender) {
            require(allowance[from][msg.sender] >= value, "Insufficient allowance");
            allowance[from][msg.sender] -= value;
        }

        if (antiSniperEnabled) {
            if (!excludedFromLimits[from]) {
                require(value <= maxTransaction, "Transfer > maxTransaction");
                require(block.timestamp - lastTransferTime[from] >= cooldownPeriod, "Cooldown active");
                lastTransferTime[from] = block.timestamp;
            }
            if (!excludedFromLimits[to]) {
                require(balanceOf[to] + value <= maxWallet, "Recipient > maxWallet");
            }
        }

        balanceOf[from] -= value;
        balanceOf[to] += value;

        emit Transfer(from, to, value);
        return true;
    }

    // AUDIT FIX (BUG-18): Same independent sender/recipient limit checks as transferFrom.
    function transfer(address to, uint256 value) external returns (bool) {
        require(balanceOf[msg.sender] >= value, "Insufficient balance");
        require(to != address(0), "Transfer to zero address");

        if (antiSniperEnabled) {
            if (!excludedFromLimits[msg.sender]) {
                require(value <= maxTransaction, "Transfer > maxTransaction");
                require(block.timestamp - lastTransferTime[msg.sender] >= cooldownPeriod, "Cooldown active");
                lastTransferTime[msg.sender] = block.timestamp;
            }
            if (!excludedFromLimits[to]) {
                require(balanceOf[to] + value <= maxWallet, "Recipient > maxWallet");
            }
        }

        balanceOf[msg.sender] -= value;
        balanceOf[to] += value;

        emit Transfer(msg.sender, to, value);
        return true;
    }

    /// LOT-34 (Audit Round 2): Lock anti-sniper so only relaxing is allowed (prevents owner from blocking sells via maxTx=1 etc.)
    function lockAntiSniperSettings() external onlyOwner {
        antiSniperLocked = true;
    }

    // LOT-34 (Audit Round 2): When antiSniperLocked, owner can only relax limits (increase maxWallet/maxTransaction, decrease cooldown).
    function updateAntiSniperSettings(
        bool _antiSniperEnabled,
        uint256 _maxWallet,
        uint256 _maxTransaction,
        uint256 _cooldownPeriod
    ) external onlyOwner {
        require(_maxWallet > 0, "Max wallet must be greater than 0");
        require(_maxTransaction > 0, "Max transaction must be greater than 0");
        require(_maxTransaction <= _maxWallet, "Max transaction must be <= max wallet");
        require(_cooldownPeriod > 0, "Cooldown period must be greater than 0");

        if (antiSniperLocked) {
            uint256 maxWalletUnscaled = maxWallet / (10 ** decimals);
            uint256 maxTxUnscaled = maxTransaction / (10 ** decimals);
            require(_maxWallet >= maxWalletUnscaled, "cannot reduce maxWallet when locked");
            require(_maxTransaction >= maxTxUnscaled, "cannot reduce maxTransaction when locked");
            require(_cooldownPeriod <= cooldownPeriod, "cannot increase cooldown when locked");
        }

        antiSniperEnabled = _antiSniperEnabled;
        maxWallet = _maxWallet * (10 ** decimals);
        maxTransaction = _maxTransaction * (10 ** decimals);
        cooldownPeriod = _cooldownPeriod;
        // LOT-23 (Audit): Emit scaled (stored) values so off-chain consumers see enforced limits
        emit AntiSniperSettingsUpdated(_antiSniperEnabled, maxWallet, maxTransaction, _cooldownPeriod);
    }

    function updateMetadata(
        string memory _description,
        string memory _logoURL,
        string memory _website,
        string memory _github,
        string memory _twitter
    ) external onlyOwner {
        description = _description;
        logoURL = _logoURL;
        website = _website;
        github = _github;
        twitter = _twitter;

        emit MetadataUpdated(_description, _logoURL, _website, _github, _twitter);
    }

    function updateProjectCategories(string[] memory _projectCategories) external onlyOwner {
        projectCategories = _projectCategories;
    }

    function updateBuyOptions(uint256[] memory _buyOptions) external onlyOwner {
        buyOptions = _buyOptions;
        emit BuyOptionsUpdated(_buyOptions);
    }

    function setExcludedFromLimits(address account, bool excluded) external onlyOwner {
        excludedFromLimits[account] = excluded;
        emit ExcludedAddressUpdated(account, excluded);
    }

    // Simple view functions to avoid stack too deep
    function getProjectCategories() external view returns (string[] memory) {
        return projectCategories;
    }

    function getBuyOptions() external view returns (uint256[] memory) {
        return buyOptions;
    }

    function isExcludedFromLimits(address account) external view returns (bool) {
        return excludedFromLimits[account];
    }

    // Internal function to set metadata during creation (called by factory)
    function _setMetadata(
        string memory _description,
        string memory _logoURL,
        string memory _website,
        string memory _github,
        string memory _twitter,
        string[] memory _projectCategories,
        uint256[] memory _buyOptions
    ) internal {
        if (bytes(_description).length > 0 || bytes(_logoURL).length > 0 || 
            bytes(_website).length > 0 || bytes(_github).length > 0 || bytes(_twitter).length > 0) {
            description = _description;
            logoURL = _logoURL;
            website = _website;
            github = _github;
            twitter = _twitter;
            emit MetadataUpdated(_description, _logoURL, _website, _github, _twitter);
        }

        if (_projectCategories.length > 0) {
            projectCategories = _projectCategories;
        }

        if (_buyOptions.length > 0) {
            buyOptions = _buyOptions;
            emit BuyOptionsUpdated(_buyOptions);
        }
    }
}

